mapper.select:
SELECT DISTINCT T1.ID AS COURSE_ID , T2.WEEK , T3.ID AS ASSIGNMENT_ID , T3.TITLE , T3.START_DT , T3.END_DT , CASE WHEN NOW() BETWEEN T3.START_DT AND T3.END_DT THEN 'Y' ELSE 'N' END AS IS_PERIOD , T4.STUDENT_ID , CASE WHEN T4.ID IS NOT NULL THEN 'Y' ELSE 'N' END AS SUB_STATUS FROM COURSES T1 INNER JOIN LECTURES T2 ON T1.ID = T2.COURSE_ID INNER JOIN ASSIGNMENTS T3 ON T1.ID = T3.COURSE_ID
AND T2.START_DT <= T3.START_DT AND T2.END_DT >= T3.END_DT
LEFT OUTER JOIN ASSIGNMENT_SUBMISSIONS T4 ON T3.ID = T4.ASSIGNMENT_ID AND T4.STUDENT_ID = #{studentId} WHERE T1.ID = #{courseId}
AND T2.WEEK = #{week}
ORDER BY T2.WEEK ASC, T3.ID ASC
